def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        temp = capacity
        multiplier = 1
        for j in range(1, 7):
            if j % 3 == 0:
                score += (item / temp) * multiplier
            elif j % 2 == 0:
                score -= np.log1p(temp) / (j + 1) * multiplier
            else:
                score += np.sqrt(item * j) / (temp + 1) * multiplier
            temp *= 0.8
            multiplier *= 1.2 if j % 2 == 0 else 0.8
        leftover = capacity - item
        if leftover < item / 2:
            score *= 2
        elif leftover > item * 5:
            score /= 1.5
        else:
            for k in range(3):
                increment = ((leftover / (k + 1)) ** 2) / (item + 1)
                if increment < 0.5:
                    score += increment * (k + 1)
                else:
                    score -= increment / (k + 2)
        if score < 0:
            score = abs(score) * 0.5
        if score > 150:
            score = 150 + np.log1p(score - 150)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_finite = np.max(finite_priorities)
        priorities[np.isinf(priorities)] = max_finite + 20
    else:
        priorities.fill(1e6)
    return priorities
